import React, { useState, useEffect } from 'react';
import { Users, UserCircle, Stethoscope, Search, ChevronRight, FileText, MapPin, Phone, MessageSquare, Clock, Trash2 } from 'lucide-react';

const DEPARTMENTS = [
  { id: 'CARD', name: 'Cardiology' }, { id: 'GYN', name: 'Gynecology' },
  { id: 'OPH', name: 'Ophthalmology' }, { id: 'PED', name: 'Pediatrics' },
  { id: 'ORTHO', name: 'Orthopedics' }, { id: 'DERM', name: 'Dermatology' },
  { id: 'NEURO', name: 'Neurology' }, { id: 'ENT', name: 'ENT' },
  { id: 'DENT', name: 'Dental' }, { id: 'GEN', name: 'General Medicine' }
];

const WAIT_PER_PATIENT = 20;

export default function SmartHospital() {
  const [view, setView] = useState('manager');
  const [currentTime, setCurrentTime] = useState(new Date());

  // --- LOCAL STORAGE LOGIC ---
  // We initialize state by checking if data exists in LocalStorage first
  const [patients, setPatients] = useState(() => {
    const saved = localStorage.getItem('hospital_patients');
    return saved ? JSON.parse(saved) : [];
  });

  const [deptTokenCounters, setDeptTokenCounters] = useState(() => {
    const saved = localStorage.getItem('hospital_counters');
    return saved ? JSON.parse(saved) : DEPARTMENTS.reduce((acc, dept) => ({ ...acc, [dept.id]: 1 }), {});
  });

  const [serving, setServing] = useState(() => {
    const saved = localStorage.getItem('hospital_serving');
    return saved ? JSON.parse(saved) : DEPARTMENTS.reduce((acc, dept) => ({ ...acc, [dept.id]: 0 }), {});
  });

  // Automatically save to LocalStorage whenever these states change
  useEffect(() => {
    localStorage.setItem('hospital_patients', JSON.stringify(patients));
  }, [patients]);

  useEffect(() => {
    localStorage.setItem('hospital_counters', JSON.stringify(deptTokenCounters));
  }, [deptTokenCounters]);

  useEffect(() => {
    localStorage.setItem('hospital_serving', JSON.stringify(serving));
  }, [serving]);
  // ---------------------------

  useEffect(() => {
    const timer = setInterval(() => setCurrentTime(new Date()), 60000);
    return () => clearInterval(timer);
  }, []);

  const [formData, setFormData] = useState({
    name: '', phone: '', age: '', gender: 'Male', address: '', complaint: '', deptId: 'CARD'
  });
  const [searchToken, setSearchToken] = useState('');

  const registerPatient = (e) => {
    e.preventDefault();
    const tokenNumber = deptTokenCounters[formData.deptId];
    const displayToken = `${formData.deptId}-${tokenNumber}`;

    const newToken = {
      displayToken,
      tokenNumber,
      ...formData,
      timeJoined: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    };

    setPatients([...patients, newToken]);
    setDeptTokenCounters(prev => ({ ...prev, [formData.deptId]: prev[formData.deptId] + 1 }));
    setFormData({ ...formData, name: '', phone: '', age: '', address: '', complaint: '' });
    alert(`Token issued: ${displayToken}`);
  };

  const nextPatient = (dId) => {
    const nextTokenNum = serving[dId] + 1;
    if (patients.some(p => p.deptId === dId && p.tokenNumber === nextTokenNum)) {
      setServing(prev => ({ ...prev, [dId]: nextTokenNum }));
    } else {
      alert(`Alert: Next patient (${dId}-${nextTokenNum}) is not registered yet.`);
    }
  };

  // Function to clear all data for a new day
  const resetSystem = () => {
    if (window.confirm("Are you sure you want to reset all tokens and patient data for today?")) {
      setPatients([]);
      setDeptTokenCounters(DEPARTMENTS.reduce((acc, dept) => ({ ...acc, [dept.id]: 1 }), {}));
      setServing(DEPARTMENTS.reduce((acc, dept) => ({ ...acc, [dept.id]: 0 }), {}));
      localStorage.clear();
    }
  };

  const calculateETA = (minutes) => {
    const eta = new Date(currentTime.getTime() + minutes * 60000);
    return eta.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-900">
      <nav className="bg-white shadow-sm p-4 flex justify-center gap-6 border-b sticky top-0 z-10">
        <button onClick={() => setView('manager')} className={`flex items-center gap-2 px-4 py-2 rounded-xl transition ${view === 'manager' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500'}`}><Users size={18}/> Staff</button>
        <button onClick={() => setView('doctor')} className={`flex items-center gap-2 px-4 py-2 rounded-xl transition ${view === 'doctor' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500'}`}><Stethoscope size={18}/> Doctors</button>
        <button onClick={() => setView('patient')} className={`flex items-center gap-2 px-4 py-2 rounded-xl transition ${view === 'patient' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500'}`}><UserCircle size={18}/> Patient View</button>
        <button onClick={resetSystem} className="flex items-center gap-2 px-4 py-2 rounded-xl text-red-500 hover:bg-red-50 transition"><Trash2 size={18}/> Reset</button>
      </nav>

      <main className="p-6 max-w-7xl mx-auto">
        {/* Registration View */}
        {view === 'manager' && (
          <div className="grid lg:grid-cols-5 gap-8">
            <div className="lg:col-span-2 bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100">
              <h2 className="text-2xl font-black mb-6 text-slate-800 tracking-tight">Registration</h2>
              <form onSubmit={registerPatient} className="space-y-4">
                <input required value={formData.name} onChange={(e) => setFormData({...formData, name: e.target.value})} placeholder="Patient Name" className="w-full p-4 border rounded-2xl bg-slate-50 outline-none" />
                <div className="grid grid-cols-2 gap-4">
                  <input required value={formData.phone} onChange={(e) => setFormData({...formData, phone: e.target.value})} placeholder="Phone" className="w-full p-4 border rounded-2xl bg-slate-50 outline-none" />
                  <input required value={formData.age} onChange={(e) => setFormData({...formData, age: e.target.value})} placeholder="Age" className="w-full p-4 border rounded-2xl bg-slate-50 outline-none" />
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <select value={formData.gender} onChange={(e) => setFormData({...formData, gender: e.target.value})} className="w-full p-4 border rounded-2xl bg-slate-50 outline-none">
                    <option>Male</option><option>Female</option><option>Other</option>
                  </select>
                  <select value={formData.deptId} onChange={(e) => setFormData({...formData, deptId: e.target.value})} className="w-full p-4 border rounded-2xl bg-slate-50 outline-none">
                    {DEPARTMENTS.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                  </select>
                </div>
                <textarea required value={formData.address} onChange={(e) => setFormData({...formData, address: e.target.value})} placeholder="Address" rows="2" className="w-full p-4 border rounded-2xl bg-slate-50 outline-none"></textarea>
                <textarea required value={formData.complaint} onChange={(e) => setFormData({...formData, complaint: e.target.value})} placeholder="Reason/Complaint" rows="3" className="w-full p-4 border rounded-2xl bg-slate-50 outline-none"></textarea>
                <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black text-lg hover:bg-blue-700 transition shadow-xl shadow-blue-100 uppercase tracking-wide">Issue {formData.deptId}-{deptTokenCounters[formData.deptId]}</button>
              </form>
            </div>

            <div className="lg:col-span-3 space-y-6">
              <h2 className="text-2xl font-black px-2 tracking-tight italic">Registrations Log</h2>
              <div className="space-y-4 max-h-[750px] overflow-y-auto pr-2">
                {patients.slice().reverse().map(p => (
                  <div key={p.displayToken} className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex justify-between items-center hover:border-blue-200 transition-all">
                    <div className="space-y-1">
                      <p className="text-3xl font-black text-blue-600 tracking-tighter">{p.displayToken}</p>
                      <h3 className="font-bold text-lg text-slate-800">{p.name} <span className="text-sm font-medium text-slate-400">({p.age}Y)</span></h3>
                      <div className="flex gap-4 text-xs font-bold text-slate-400 pt-2 uppercase tracking-widest">
                        <span className="flex items-center gap-1"><Phone size={12}/> {p.phone}</span>
                        <span className="flex items-center gap-1"><Clock size={12}/> {p.timeJoined}</span>
                      </div>
                    </div>
                    <div className="text-right">
                      <span className="px-4 py-2 bg-slate-100 rounded-full text-[10px] font-black uppercase tracking-widest text-slate-500">{DEPARTMENTS.find(d => d.id === p.deptId)?.name}</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* Doctor Dashboard */}
        {view === 'doctor' && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {DEPARTMENTS.map(d => (
              <div key={d.id} className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm transition-all hover:shadow-xl">
                <div className="flex justify-between items-center mb-8">
                  <h3 className="font-black text-xl text-slate-800">{d.name}</h3>
                  <div className="flex flex-col items-end">
                    <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest">Queue</span>
                    <span className="text-xl font-black">{patients.filter(p => p.deptId === d.id && p.tokenNumber > serving[d.id]).length}</span>
                  </div>
                </div>
                <div className="text-center py-10 bg-slate-900 text-white rounded-[2rem] mb-6 relative overflow-hidden">
                  <p className="text-[10px] opacity-50 uppercase font-black tracking-widest mb-2 text-blue-400">Current Serving</p>
                  <p className="text-7xl font-black tracking-tighter">{d.id}-{serving[d.id]}</p>
                </div>
                <button onClick={() => nextPatient(d.id)} className="w-full flex justify-center items-center gap-2 bg-blue-600 text-white py-5 rounded-2xl font-black text-lg hover:bg-blue-700 transition">Call Next Patient <ChevronRight/></button>
              </div>
            ))}
          </div>
        )}

        {/* Patient View */}
        {view === 'patient' && (
          <div className="max-w-xl mx-auto text-center mt-12 animate-in fade-in duration-700">
            <h1 className="text-5xl font-black text-slate-900 mb-4 tracking-tighter italic">Queue Tracker</h1>
            <p className="text-slate-400 mb-10 text-lg">Hospital token monitoring system</p>
            <div className="relative mb-12 group">
              <input type="text" onChange={(e) => setSearchToken(e.target.value.toUpperCase())} placeholder="e.g. CARD-1" className="w-full p-6 pl-16 border-2 border-slate-200 rounded-3xl text-3xl font-black focus:border-blue-500 outline-none uppercase transition-all shadow-sm" />
              <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-300" size={32} />
            </div>
            
            {searchToken && patients.find(p => p.displayToken === searchToken) ? (
              (() => {
                const p = patients.find(p => p.displayToken === searchToken);
                const currentServingNum = serving[p.deptId];
                const opsAhead = p.tokenNumber - currentServingNum;
                const totalWaitMinutes = opsAhead * WAIT_PER_PATIENT;

                return opsAhead > 0 ? (
                  <div className="bg-white p-10 rounded-[3rem] shadow-2xl border border-slate-50 relative overflow-hidden">
                    <p className="text-blue-600 uppercase tracking-[0.3em] text-xs font-black mb-4">{DEPARTMENTS.find(d => d.id === p.deptId).name}</p>
                    <div className="flex justify-around items-center mb-10">
                        <div className="text-left">
                            <p className="text-[10px] text-slate-400 uppercase font-bold mb-1">Serving Now</p>
                            <p className="text-5xl font-black text-slate-900">{p.deptId}-{currentServingNum}</p>
                        </div>
                        <div className="text-right">
                            <p className="text-[10px] text-slate-400 uppercase font-bold mb-1">Your Token</p>
                            <p className="text-5xl font-black text-blue-600">{p.displayToken}</p>
                        </div>
                    </div>
                    <div className="grid grid-cols-2 gap-6 pt-8 border-t border-slate-50">
                      <div className="bg-slate-50 p-6 rounded-3xl text-left">
                        <p className="text-[10px] text-slate-400 uppercase font-black mb-1">Estimated Time</p>
                        <p className="text-2xl font-black text-slate-800">{calculateETA(totalWaitMinutes)}</p>
                      </div>
                      <div className="bg-red-50 p-6 rounded-3xl text-right">
                        <p className="text-[10px] text-red-400 uppercase font-black mb-1">Wait Time</p>
                        <p className="text-2xl font-black text-red-600">~{totalWaitMinutes}m</p>
                      </div>
                    </div>
                  </div>
                ) : (
                  <div className="bg-green-600 p-12 rounded-[3rem] shadow-xl text-white">
                    <p className="text-xl font-black mb-2 uppercase tracking-widest">Your Turn!</p>
                    <p className="text-5xl font-black mb-4">{p.displayToken}</p>
                    <p className="text-sm font-bold opacity-80">Proceed to {DEPARTMENTS.find(d => d.id === p.deptId).name} now.</p>
                  </div>
                );
              })()
            ) : null}
          </div>
        )}
      </main>
    </div>
  );
}
